// Find the first product link in the search results
const firstProduct = document.querySelector('[data-component-type="s-search-result"]');
if (firstProduct) {
  const link = firstProduct.querySelector('h2 a');
  if (link) {
    return {
      title: link.innerText,
      url: link.href
    };
  }
}
return null;

(function() {
  const firstProduct = document.querySelector('[data-component-type="s-search-result"]');
  if (firstProduct) {
    const link = firstProduct.querySelector('h2 a');
    if (link) {
      return {
        title: link.innerText,
        url: link.href
      };
    }
  }
  return null;
})();

(function() {
  // Try to find product links in the results
  const productLink = document.querySelector('.s-result-item h2 a');
  if (productLink) {
    return {
      title: productLink.innerText,
      url: productLink.href
    };
  }
  return null;
})();

(function() {
  const productLink = document.querySelector('.s-result-item h2 a');
  if (productLink) {
    return JSON.stringify({
      title: productLink.innerText,
      url: productLink.href
    });
  }
  return null;
})();

(function() {
  // Find all product items, excluding ads
  const products = document.querySelectorAll('[data-component-type="s-search-result"]');
  for (let product of products) {
    // Skip if it's a sponsored ad in the header area
    if (product.querySelector('[data-component-type="sp-sponsored-result"]')) {
      continue;
    }
    const link = product.querySelector('h2 a');
    if (link) {
      return JSON.stringify({
        title: link.innerText.trim(),
        url: link.href
      });
    }
  }
  return null;
})();

(function() {
  const products = [];
  const links = document.querySelectorAll('h2 a[href*="/dp/"]');
  for (let i = 0; i < Math.min(5, links.length); i++) {
    products.push({
      title: links[i].innerText.trim(),
      url: links[i].href
    });
  }
  return JSON.stringify(products);
})();

(function() {
  const links = document.querySelectorAll('a[href*="/dp/"]');
  const products = [];
  for (let i = 0; i < Math.min(5, links.length); i++) {
    const text = links[i].innerText.trim();
    if (text.length > 10) {
      products.push({
        title: text.substring(0, 100),
        url: links[i].href
      });
    }
  }
  return JSON.stringify(products);
})();

(function() {
  const links = document.querySelectorAll('a');
  const products = [];
  for (let link of links) {
    const text = link.innerText.trim();
    if (text.includes('Sock Amazing') || text.includes('Bamboo Rayon')) {
      products.push({
        title: text.substring(0, 150),
        url: link.href
      });
      if (products.length >= 3) break;
    }
  }
  return JSON.stringify(products);
})();

